    "id": 14,
    "slug": "supermassive-black-holes-could-merge-in-100-years",
    "cat": "Astrofísica",
    "catCls": "astrofisica",
    "img": "https://earthsky.org/upl/2026/04/2-supermassive-black-holes-collide-MPIfRA-AI-e1775757576289.png",
    "inline_images": [],
    "video": null,
